import { useState } from 'preact/hooks';
import type { AppState } from '../state';
import { setUser } from '../state';
import { getToken, logout } from '../auth';

interface SettingsPanelProps {
  state: AppState;
  onClose: () => void;
}

export function SettingsPanel({ state, onClose }: SettingsPanelProps) {
  const { user } = state;
  if (!user) return null;

  const [saving, setSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [showPurgeConfirm, setShowPurgeConfirm] = useState(false);
  const [purgePassword, setPurgePassword] = useState('');

  const updatePreference = async (key: string, value: boolean) => {
    setSaving(true);
    setError(null);
    try {
      const token = getToken();
      const response = await fetch('/api/auth/preferences', {
        method: 'PATCH',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({ [key]: value })
      });

      if (!response.ok) throw new Error('Failed to update preferences');

      // Optimistically update local state
      setUser({
        ...user,
        [key]: value
      });
    } catch (err) {
      setError('COMM_FAILURE: Preferences not synchronized.');
    } finally {
      setSaving(false);
    }
  };

  const toggleMarketing = async (value: boolean) => {
    setSaving(true);
    setError(null);
    try {
      const token = getToken();
      const response = await fetch('/api/auth/preferences', {
        method: 'PATCH',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({ marketingConsent: value })
      });

      if (!response.ok) throw new Error('Failed to update preferences');

      setUser({
        ...user,
        marketingConsentAt: value ? new Date().toISOString() : null
      });
    } catch (err) {
      setError('COMM_FAILURE: Preferences not synchronized.');
    } finally {
      setSaving(false);
    }
  };

  const handlePurge = async () => {
    if (!purgePassword) return;
    setSaving(true);
    setError(null);
    try {
      const token = getToken();
      const response = await fetch('/api/auth/account', {
        method: 'DELETE',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({ password: purgePassword })
      });

      if (response.status === 401) {
        setError('AUTH_FAILURE: Incorrect authorization code.');
        return;
      }

      if (!response.ok) throw new Error('Purge failed');

      // Success! User is gone.
      await logout();
      window.location.reload();
    } catch (err) {
      setError('CRITICAL_FAILURE: The Purge could not be initialized.');
    } finally {
      setSaving(false);
    }
  };

  return (
    <div class="auth-panel brutalist-panel">
      <div class="auth-header">
        <h2 class="auth-title">OPERATIVE_SETTINGS</h2>
        <button class="auth-close" onClick={onClose}>×</button>
      </div>

      {error && <div class="auth-error" style="margin-bottom: 1rem">{error}</div>}

      <div class="settings-group">
        <h3 class="settings-label">COMMUNICATION_CHANNELS</h3>

        <div class="setting-row">
          <div class="setting-info">
            <span class="setting-name">TRANSACTIONAL_UPLINK</span>
            <span class="setting-desc">Critical alerts, password resets, and security notices.</span>
          </div>
          <div class="brutalist-toggle active">MANDATORY</div>
        </div>

        <div class="setting-row">
          <div class="setting-info">
            <span class="setting-name">ENGAGEMENT_ALERTS</span>
            <span class="setting-desc">Notifications for match starts and turn reminders.</span>
          </div>
          <button 
            class={`brutalist-toggle ${user.reminderNotifications ? 'active' : ''}`}
            disabled={saving}
            onClick={() => updatePreference('reminderNotifications', !user.reminderNotifications)}
          >
            {user.reminderNotifications ? 'ENABLED' : 'DISABLED'}
          </button>
        </div>

        <div class="setting-row">
          <div class="setting-info">
            <span class="setting-name">MARKETING_BEACON</span>
            <span class="setting-desc">News, promotional offers, and tactical updates (TCPA compliant).</span>
          </div>
          <button 
            class={`brutalist-toggle ${user.marketingConsentAt ? 'active' : ''}`}
            disabled={saving}
            onClick={() => toggleMarketing(!user.marketingConsentAt)}
          >
            {user.marketingConsentAt ? 'AUTHORIZED' : 'DE-AUTHORIZED'}
          </button>
        </div>
      </div>

      <div class="settings-group" style="margin-top: 2rem">
        <h3 class="settings-label">DATA_SOVEREIGNTY</h3>
        <p class="setting-desc" style="margin-bottom: 1rem">
          You have the right to be forgotten. Purging your account will permanently delete your identity and anonymize your combat history.
        </p>

        {!showPurgeConfirm ? (
          <button 
            class="btn btn-danger" 
            style="width: 100%; letter-spacing: 2px"
            onClick={() => setShowPurgeConfirm(true)}
          >
            INITIALIZE_THE_PURGE
          </button>
        ) : (
          <div class="purge-confirm-zone" style="border: 2px solid var(--neon-red); padding: 1rem">
            <p class="warning-text" style="color: var(--neon-red); font-weight: 900; margin-bottom: 1rem">
              WARNING: This action is IRREVERSIBLE.
            </p>
            <input 
              type="password"
              class="name-input"
              style="margin-bottom: 1rem"
              placeholder="CONFIRM_PASSWORD"
              value={purgePassword}
              onInput={(e) => setPurgePassword(e.currentTarget.value)}
            />
            <div style="display: flex; gap: 8px">
              <button 
                class="btn btn-danger" 
                style="flex: 1"
                disabled={saving || !purgePassword}
                onClick={handlePurge}
              >
                {saving ? 'PURGING...' : 'CONFIRM_PURGE'}
              </button>
              <button 
                class="btn btn-secondary" 
                style="flex: 1"
                onClick={() => setShowPurgeConfirm(false)}
              >
                ABORT
              </button>
            </div>
          </div>
        )}
      </div>

      <div class="auth-footer" style="margin-top: 2rem; opacity: 0.5; font-size: 0.6rem">
        LEGAL_CONSENT_v1.0 | GDPR/TCPA_READY
      </div>
    </div>
  );
}

/**
 * OpenTelemetry Web Instrumentation for Phalanx Duel Client.
 * Routes traces and metrics to the local OTel collector via HTTP/protobuf.
 */

/* eslint-disable @typescript-eslint/no-unsafe-call, @typescript-eslint/no-explicit-any */

import { metrics } from '@opentelemetry/api';
import { registerInstrumentations } from '@opentelemetry/instrumentation';
import { FetchInstrumentation } from '@opentelemetry/instrumentation-fetch';
import { XMLHttpRequestInstrumentation } from '@opentelemetry/instrumentation-xml-http-request';
import { WebTracerProvider } from '@opentelemetry/sdk-trace-web';
import { BatchSpanProcessor } from '@opentelemetry/sdk-trace-web';
import { OTLPTraceExporter } from '@opentelemetry/exporter-trace-otlp-http';
import { MeterProvider, PeriodicExportingMetricReader } from '@opentelemetry/sdk-metrics';
import { OTLPMetricExporter } from '@opentelemetry/exporter-metrics-otlp-http';
import { resourceFromAttributes } from '@opentelemetry/resources';
import { ATTR_SERVICE_NAME } from '@opentelemetry/semantic-conventions';
import { ZoneContextManager } from '@opentelemetry/context-zone';

const urlParams = new URLSearchParams(window.location.search);
const isLocalHost =
  window.location.hostname === 'localhost' ||
  window.location.hostname === '127.0.0.1' ||
  window.location.hostname === '::1';
const telemetryDisabled =
  urlParams.get('telemetry') === 'off' ||
  urlParams.get('telemetry') === '0' ||
  localStorage.getItem('phx_telemetry_disabled') === '1' ||
  (window as typeof window & { __PHX_TELEMETRY_DISABLED__?: boolean })
    .__PHX_TELEMETRY_DISABLED__ === true ||
  (!isLocalHost && urlParams.get('telemetry') !== 'on');
// In development, we point to the host-based collector.
const OTEL_BASE_URL = urlParams.get('otelBaseUrl')?.trim() || 'http://127.0.0.1:4318';
const deploymentEnvironment = import.meta.env.MODE || 'development';
const serviceInstanceId = `browser:${window.location.host}:${crypto.randomUUID()}`;

const resource = resourceFromAttributes({
  [ATTR_SERVICE_NAME]: 'phx-client',
  'service.namespace': 'phalanxduel',
  'service.version': __APP_VERSION__,
  'deployment.environment': deploymentEnvironment,
  'service.instance.id': serviceInstanceId,
});

if (!telemetryDisabled) {
  // 1. Initialize Tracing
  const tracerProvider = new WebTracerProvider({
    resource,
    spanProcessors: [
      new BatchSpanProcessor(
        new OTLPTraceExporter({
          url: `${OTEL_BASE_URL}/v1/traces`,
        }),
      ),
    ],
  });

  tracerProvider.register({
    contextManager: new ZoneContextManager(),
  });

  // 2. Initialize Metrics
  const metricExporter = new OTLPMetricExporter({
    url: `${OTEL_BASE_URL}/v1/metrics`,
  });

  const meterProvider = new MeterProvider({
    resource,
    readers: [
      new PeriodicExportingMetricReader({
        exporter: metricExporter,
        exportIntervalMillis: 10000,
      }),
    ],
  });

  metrics.setGlobalMeterProvider(meterProvider);
}

// 3. Register automatic instrumentations
registerInstrumentations({
  instrumentations: [
    new (FetchInstrumentation as any)({
      // Propagate trace context to the server
      propagateTraceHeaderCorsUrls: [/http:\/\/127.0.0.1:3001\/.*/, /http:\/\/127.0.0.1:3001\/.*/],
    }),
    new (XMLHttpRequestInstrumentation as any)({
      propagateTraceHeaderCorsUrls: [/http:\/\/127.0.0.1:3001\/.*/, /http:\/\/127.0.0.1:3001\/.*/],
    }),
  ],
});

console.log(
  telemetryDisabled
    ? '[phx-client] Telemetry disabled for this browser session'
    : `[phx-client] Telemetry active: phx-client -> ${OTEL_BASE_URL}`,
);

import type {
  PhalanxTurnResult,
  TransactionLogEntry,
  CombatLogEntry,
  CombatLogStep,
  CombatBonusType,
  GamePhase,
  Card,
  Suit,
} from '@phalanxduel/shared';
import { cardLabel } from './cards';
import type { NarrationBus, NarrationEntry } from './narration-bus';
import type { CardType } from './narration-bus';

// ── Timing Constants ─────────────────────────────

const DELAY_ATTACK = 800;
const DELAY_DESTROYED = 400;
const DELAY_OVERFLOW = 600;
const DELAY_DEPLOY = 600;
const DELAY_BONUS = 500;
const DELAY_PHASE = 400;

// ── Card Classification ──────────────────────────

function classifyCard(card: Card): CardType {
  if (card.type === 'ace') return 'ace';
  if (['jack', 'queen', 'king'].includes(card.type)) return 'face';
  return 'number';
}

// ── Card Lookup ─────────────────────────────────
// Card IDs are opaque — look up card data from game state instead of parsing IDs.

// ── Bonus Messages ───────────────────────────────

const BONUS_MESSAGES: Partial<Record<CombatBonusType, (card: string) => string>> = {
  aceInvulnerable: (card) => `${card} is invulnerable`,
  aceVsAce: (card) => `${card} breaks through invulnerability`,
  diamondDoubleDefense: () => '...absorbed by Diamond Defense',
  clubDoubleOverflow: () => '...doubled by Club Overflow',
  spadeDoubleLp: () => '...doubled by Spade direct strike',
  heartDeathShield: (card) => `${card} survives — Heart Shield`,
  diamondDeathShield: (card) => `${card} survives — Diamond Shield`,
};

// Bonuses that are suppressed (no narration)
const SUPPRESSED_BONUSES = new Set<CombatBonusType>(['faceCardIneligible']);

/**
 * NarrationProducer — converts transaction log diffs into NarrationEntry sequences.
 *
 * Hooks into the game state update flow via onTurnResult. It diffs the transaction
 * log to find new entries, converts them to narration events with appropriate timing,
 * and enqueues them on the NarrationBus.
 */
export class NarrationProducer {
  private lastLogCount = 0;
  private lastPhase: GamePhase | null = null;
  private initialized = false;

  constructor(private readonly bus: NarrationBus) {}

  onTurnResult(result: PhalanxTurnResult): void {
    const { postState } = result;

    // Seed tracking on first call — prevents replaying history
    if (!this.initialized) {
      this.lastLogCount = postState.transactionLog?.length ?? 0;
      this.lastPhase = postState.phase;
      this.initialized = true;
      return;
    }

    const entries: NarrationEntry[] = [];

    // Phase change detection
    if (postState.phase !== this.lastPhase) {
      entries.push({
        event: { type: 'phase-change', phase: postState.phase },
        delayMs: DELAY_PHASE,
      });
      this.lastPhase = postState.phase;
    }

    // Diff transaction log
    const currentLogCount = postState.transactionLog?.length ?? 0;
    if (currentLogCount > this.lastLogCount) {
      const newTxEntries = postState.transactionLog?.slice(this.lastLogCount) ?? [];
      // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
      const columns = postState.params?.columns ?? 6;
      for (const txEntry of newTxEntries) {
        const produced = this.processTxEntry(txEntry, postState.players, columns);
        entries.push(...produced);
      }
      this.lastLogCount = currentLogCount;
    }

    if (entries.length > 0) {
      this.bus.enqueue(entries);
    }
  }

  private processTxEntry(
    txEntry: TransactionLogEntry,
    players: PhalanxTurnResult['postState']['players'],
    columns: number,
  ): NarrationEntry[] {
    const { action, details } = txEntry;

    // system:init has no playerIndex — skip it
    if (action.type === 'system:init') return [];

    const playerName = players[action.playerIndex]?.player.name ?? 'Unknown';

    switch (details.type) {
      case 'deploy':
        return this.processDeployEntry(playerName, action, {
          gridIndex: details.gridIndex,
          columns,
          players,
        });
      case 'pass':
        return this.processPassEntry(playerName, players);
      case 'attack':
        return this.processAttackEntry(details.combat, players);
      case 'reinforce':
      case 'forfeit':
        return [];
      default:
        return [];
    }
  }

  private processDeployEntry(
    playerName: string,
    action: TransactionLogEntry['action'],
    ctx: {
      gridIndex: number;
      columns: number;
      players: PhalanxTurnResult['postState']['players'];
    },
  ): NarrationEntry[] {
    if (action.type !== 'deploy') return [];

    // Look up the deployed card from the battlefield (post-state) instead of parsing the ID.
    const bfCard = ctx.players[action.playerIndex]?.battlefield[ctx.gridIndex];
    const cardObj = bfCard?.card;
    const card = cardObj ? cardLabel(cardObj) : 'card';
    const suit = cardObj?.suit ?? 'spades';
    const cardType = cardObj ? classifyCard(cardObj) : 'number';
    const column = ctx.gridIndex % ctx.columns;
    const row = Math.floor(ctx.gridIndex / ctx.columns);

    return [
      {
        event: {
          type: 'deploy',
          player: playerName,
          card,
          suit,
          cardType,
          column,
          row,
        },
        delayMs: DELAY_DEPLOY,
      },
    ];
  }

  private processPassEntry(
    _playerName: string,
    _players: PhalanxTurnResult['postState']['players'],
  ): NarrationEntry[] {
    // Pass is an internal turn-alternation mechanic, not a meaningful player action.
    // Suppress in all phases to keep narration focused on actual game events.
    return [];
  }

  private processAttackEntry(
    combat: CombatLogEntry,
    players: PhalanxTurnResult['postState']['players'],
  ): NarrationEntry[] {
    const entries: NarrationEntry[] = [];
    const defenderIdx = combat.attackerPlayerIndex === 0 ? 1 : 0;
    const defenderName = players[defenderIdx]?.player.name ?? 'Opponent';
    const attackerLabel = cardLabel(combat.attackerCard);
    const attackerSuit = combat.attackerCard.suit;
    const attackerCardType = classifyCard(combat.attackerCard);

    for (const step of combat.steps) {
      // Check for suppressed bonuses
      if (this.hasSuppressedBonusOnly(step)) continue;

      // Zero damage with no bonus — suppress entirely
      if (step.damage === 0 && !this.hasNarratableBonus(step)) continue;

      // Generate bonus callouts for zero-damage steps with bonuses
      if (step.damage === 0 && this.hasNarratableBonus(step)) {
        entries.push(...this.generateBonusEntries(step, attackerSuit));
        continue;
      }

      const targetSuit = step.card?.suit;
      const targetCardType = step.card ? classifyCard(step.card) : undefined;

      // Normal damage steps
      switch (step.target) {
        case 'frontCard':
        case 'backCard': {
          const targetLabel = step.card ? cardLabel(step.card) : 'card';

          if (step.target === 'backCard') {
            entries.push({
              event: {
                type: 'overflow',
                target: targetLabel,
                damage: step.damage,
                suit: targetSuit,
              },
              delayMs: DELAY_OVERFLOW,
            });
          } else {
            entries.push({
              event: {
                type: 'attack',
                attacker: attackerLabel,
                target: targetLabel,
                damage: step.damage,
                suit: attackerSuit,
                cardType: attackerCardType,
              },
              delayMs: DELAY_ATTACK,
            });
          }

          if (step.destroyed) {
            entries.push({
              event: {
                type: 'destroyed',
                card: targetLabel,
                suit: targetSuit,
                cardType: targetCardType,
              },
              delayMs: DELAY_DESTROYED,
            });
          }

          if (this.hasNarratableBonus(step)) {
            entries.push(...this.generateBonusEntries(step, attackerSuit));
          }
          break;
        }
        case 'playerLp': {
          entries.push({
            event: {
              type: 'lp-damage',
              player: defenderName,
              damage: step.damage,
              suit: attackerSuit,
            },
            delayMs: DELAY_ATTACK,
          });

          if (this.hasNarratableBonus(step)) {
            entries.push(...this.generateBonusEntries(step, attackerSuit));
          }
          break;
        }
      }
    }

    return entries;
  }

  private hasSuppressedBonusOnly(step: CombatLogStep): boolean {
    const bonuses = step.bonuses ?? [];
    if (bonuses.length === 0) return false;
    return bonuses.every((b) => SUPPRESSED_BONUSES.has(b));
  }

  private hasNarratableBonus(step: CombatLogStep): boolean {
    const bonuses = step.bonuses ?? [];
    return bonuses.some((b) => !SUPPRESSED_BONUSES.has(b) && BONUS_MESSAGES[b] !== undefined);
  }

  private generateBonusEntries(step: CombatLogStep, attackerSuit?: Suit): NarrationEntry[] {
    const bonuses = step.bonuses ?? [];
    const cardLbl = step.card ? cardLabel(step.card) : 'card';
    const stepSuit = step.card?.suit ?? attackerSuit;
    const stepCardType = step.card ? classifyCard(step.card) : undefined;
    const entries: NarrationEntry[] = [];

    for (const bonus of bonuses) {
      if (SUPPRESSED_BONUSES.has(bonus)) continue;
      const msgFn = BONUS_MESSAGES[bonus];
      if (!msgFn) continue;

      entries.push({
        event: {
          type: 'bonus',
          bonus,
          card: cardLbl,
          message: msgFn(cardLbl),
          suit: stepSuit,
          cardType: stepCardType,
        },
        delayMs: DELAY_BONUS,
      });
    }

    return entries;
  }
}

